sp_css.css:
/*
Collection of CSS that is used in multiple widgets
2.8 | 2022-05-13 | raj  | STRY0121805 - Homepage UI Update- New Design for Colorful Filter and "Show More Filters" dropdown

2.8 | 2022-05-13 | mmcc | DFCT0010887 - New button is gone from Template List page
2.8 | 2022-05-13 | mmcc | DFCT0010911 - Templates modal  forms are NOT displaying at ALL

2.8 | 2022-03-24 | mmcc | STRY0115677 - Org Hierarchy Full Screen- Process Request Indicator- Popover Styling
Added list outer container CSS to support 2 different widths, Using before/after CSS to show arrow without box-shadow issues
Dropped some unused selectors

2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
Added #popoverWrapperList, .dtech-popover-list-outer-container, .dtech-avatar-round-32rem, .dtech-margin-bottom-inherit
Added 2022-03-16 .dtech-box-shadow, .dtech-popover-list-main-container, .dtech-popover-list-spinner-content, .dtech-popover-list-footer-content 

2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
Added .dtech-pad-left-0, dtech-pad-left-5, dtech-pad-left-10
Added .dtech-pad-right-0, dtech-pad-right-5, dtech-pad-right-10
Added .dtech-pad-top-0, dtech-pad-top-5, dtech-pad-top-10
Added sections for GoJS popover start/end and profile photo start/end

2.8 | 2022-02-02 | mmcc | STRY0117664 - 508 WCAG Compliance Add .selected CSS to Tasker Theme
Move .selected CSS selector from widget to theme in order to have one style for DocInt and Tasker;
Removed invalid CSS, does not accept width and style, only color -> border-color: 1px solid #fff; 
see #dtech-list-1 .selected
2.7.2 | 2021-12-27 | mmcc | DFCT0010728 - Modal Scheduled Tasks shows title data with an ellipsis
*/
.TaskerOverallStyleSheet { display: none; } /* Name of Style Sheet, do not use to style HTML */

/* GoJS popover start */

/* STRY0121805 - this setting uses flex box row with wrap and center for the header row*/
.dtech-header-row{
  display: flex;
  flex-flow: row nowrap;
  justify-content:center;
  align-items:start;
}
/* STRY0121805 - this setting uses flex box row with wrap and center for the counter row*/
.dtech-count-row{
  display: flex;
  flex-flow: row wrap;
  justify-content:center;
  align-items:center;
}
/* STRY0121805 - this sets the width for all of the count items */
.dtech-count-column {
  width: 230px;
  padding-bottom: 10px;
}

/* STRY0121805 - this sets the bottom padding menu items */
.dtech-header-column {
  padding-bottom: 10px;
}

#popoverWrapper {
  display: none;
  position: absolute;
  z-index: 1000;
}

#popoverWrapperList {
  display: none;
  position: absolute;
  z-index: 1100;
}

.dtech-popover-container-avatar {
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  height: 365px;
  padding: 30px 20px 20px 20px;
  position: absolute;
  width: 400px;
  
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}

.dtech-popover-list-outer-container-lg {
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  /* height: 365px; not needed since flex */
  display: flex;
  flex-flow: column nowrap;
  min-height: 100px;
  padding: 10px 20px;
  position: absolute;
  width: 250px; /* was 200px when font-size was 14px */
  
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}

.dtech-arrow-up:before {
  border-bottom: 10px solid $tasker-popover-arrow-color;
  border-left: 10px solid transparent;
  border-right: 10px solid transparent;
  content: '';
  height: 0;
  left: calc(100% / 2 - 10px);
  position: absolute;
  /* right: 50%; */
  top: -10px;
  width: 0;
  z-index: 2;
}

.dtech-arrow-up:after {
  border-bottom: 12px solid rgba(0, 0, 0, 0.1);
  border-left: 12px solid transparent;
  border-right: 12px solid transparent;
  content: '';
  height: 0;
  left: calc(100% /2 - 12px);
  position: absolute;
  /* right: 49%; */
  top: -12px; 
  width: 0;
  z-index: 1;
}

.dtech-popover-list-outer-container-md {
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  /* height: 365px; not needed since flex */
  display: flex;
  flex-flow: column nowrap;
  min-height: 40px;
  /* min-width: 165px; */
  padding: 10px 20px;
  position: absolute;
  /* width: 200px; */
  width: max-content;
  
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}

.dtech-popover-list-main-container {
  flex-flow: row nowrap;
  display: flex;
  flex: 1;
  max-height: 290px;
  overflow-y: auto;
}

.dtech-popover-list-spinner-content {
  align-self: center;
  flex: 1 1 auto;
  text-align: center;
}

.dtech-popover-list-footer-content {
  margin-left: 3.2rem; /* match width of dtech-avatar-round-* */
  margin-top: 20px; /* li has margin-bottom 10px for a total of 30px */
}

.dtech-footer-row-sticky {
  bottom: 20px;
  margin-top: 20px;
  position: absolute;
  width: calc(100% - 40px);
}

.dtech-opacity-50 {
  opacity: 0.5;
}

.dtech-avatar-text-standard-14 {
  color: $tasker-text-standard-color;
  font-size: 14px;
}

.dtech-avatar-text-standard-16 {
  color: $tasker-text-standard-color;
  font-size: 16px;
}

.dtech-avatar-link {
  color: $tasker-link-color;
  font-size: 16px;
  text-decoration-line: underline;
  text-decoration-color: $tasker-link-color;
  text-decoration-style: solid;
}

/* profile photo start */
.dtech-avatar-round-32rem {
  cursor: default;
  height: 3.2rem;
  width: 3.2rem;
}

.dtech-avatar-round-64rem {
  cursor: default;
  height: 6.4rem;
  width: 6.4rem;
}

.dtech-avatar-bg-color {
  background-color: $tasker-avatar-bg-color !important;
  background-repeat: no-repeat !important; 
}

.dtech-avatar-bg-color-transparent {
  background-color: transparent !important;
}

/* profile photo end */
/* GoJS popover end */

/* DFCT0010887 & DFCT0010911 Template Pages start */
.dtech-fill-section {
    position: relative;
    overflow-y: auto;
    height: calc(100vh - 350px);
}
/* DFCT0010887 & DFCT0010911 Template Pages end */

#dtech-list-1 .selected {
  color: $taskerdatatable-selected-row-text;
  background-color: $taskerdatatable-selected-row-bg;
}

.dtech-box {
  display: flex;
}

/* Must be a descendant of the class dtech-box */
.dtech-box .dtech-push-right {
  margin-left: auto!important;
}

.dtech-disabled{
  pointer-events: none;
  cursor:default;
  opacity:50%;
}

.dtech-enabled{
  pointer-events: auto;
  cursor:pointer;
  opacity:100%;
}

.dtech-margin-bottom-inherit {
  margin-bottom: inherit;
}

.dtech-margin-top-4px {
  margin-top: 4px;
}

.dtech-margin-top-5px {
  margin-top: 5px;
}

.dtech-max-width-fit-content {
  max-width: fit-content;
}

.dtech-pad-all-10 {
  padding: 10px;
}

/* STRY0121805 */
.dtech-pad-botton-5 {
  padding-bottom: 5px;
}
.dtech-pad-bottom-10 {
  padding-bottom: 10px;
}

.dtech-pad-left-0 {
  padding-left: 0;
}

.dtech-pad-left-5 {
  padding-left: 5px;
}

.dtech-pad-left-10 {
  padding-left: 10px;
}

.dtech-pad-right-0 {
  padding-right: 0;
}

.dtech-pad-right-5 {
  padding-right: 5px;
}

.dtech-pad-right-10 {
  padding-right: 10px;
}

.dtech-pad-top-0 {
  padding-top: 0;
}

.dtech-pad-top-5 {
  padding-top: 5px;
}

.dtech-pad-top-10 {
  padding-top: 10px;
}

.dtech-push-right-flexbox {
  margin-left: auto;
}

.dtech-text-center {
  text-align: center;
}
